// n8n Code Node - 檢查 house_id 重複並添加標籤
// 這段程式碼應該放在 n8n 的 Code Node 中

// 獲取輸入數據
const items = $input.all();

// 建立一個 Map 來計算每個 house_id 出現的次數
const houseIdCount = new Map();

// 第一次遍歷：計算每個 house_id 的出現次數
items.forEach(item => {
  const houseId = item.json.house_id;
  if (houseId !== undefined && houseId !== null) {
    houseIdCount.set(houseId, (houseIdCount.get(houseId) || 0) + 1);
  }
});

// 第二次遍歷：為每個項目添加 same_house 標籤
const outputItems = items.map(item => {
  const houseId = item.json.house_id;

  // 檢查這個 house_id 是否出現兩次或以上
  const isSameHouse = houseIdCount.get(houseId) >= 2;

  // 建立新的物件，包含原始數據和新的 same_house 標籤
  return {
    json: {
      ...item.json,
      same_house: isSameHouse
    }
  };
});

// 返回處理後的數據
return outputItems;

// CO2 資料轉換為 CSV 二進位檔案
// 這個節點只執行一次，處理所有項目

// 1. 從前一個節點取得所有項目
const allCO2Data = $input.all();

// Count how many non-zero values exist
const nonZeroCount = allCO2Data.filter(item => {
  const co2Value = item.json.co2;
  return co2Value !== null && co2Value !== undefined && co2Value !== 0;
}).length;

// Check if nonZeroCount is 47 or 48
const checkResult = (nonZeroCount === 47 || nonZeroCount === 48) ? "yes" : "no";

// 2. 從資料創建 CSV 字串（移除 RecordedBy 欄位）
let csvContent = "CO2,CreatedAt\n"; // CSV 標頭 - 只保留兩欄

for (const item of allCO2Data) {
  const data = item.json;
  // 處理 null 值：如果 co2 為 null 或 undefined，則使用 0
  const co2Value = data.co2 !== null && data.co2 !== undefined ? data.co2 : 0;
  // 處理 CSV 格式，確保日期時間正確格式化（移除第三欄）
  const row = `${co2Value},"${data.created_at}"`;
  csvContent += row + "\n";
}

// 3. 取得 room_id 和 date 並組成動態檔案名稱（包含星期幾縮寫）
const roomId = $('set room id').first().json.room_id;
const date = $('set room id').first().json.query_date;

// 計算星期幾（3字母縮寫）
const dateObj = new Date(date);
const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const dayOfWeek = dayNames[dateObj.getDay()];

const fileName = `room_${roomId}_${date}_co2_report_${dayOfWeek}.csv`;

// 4. 使用助手函數從字串創建二進位檔案
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(csvContent), 
  fileName
);

// Count how many zeros exist
const zeroCount = allCO2Data.length - nonZeroCount;

// 5. 返回包含二進位資料的新項目
return [
  {
    json: {
      reportGenerated: new Date().toISOString(),
      recordCount: allCO2Data.length,
      allNonZeroCheck: checkResult,  // "yes" if nonZeroCount is 47 or 48, "no" otherwise
      zeroCount: zeroCount,  // Number of zero values
      nonZeroCount: nonZeroCount,  // Number of non-zero values
      room_id: roomId,
      query_date: date,
      // 計算統計資料時也要處理 null 值
      averageCO2: Math.round(allCO2Data.reduce((sum, item) => {
        const co2Value = item.json.co2 !== null && item.json.co2 !== undefined ? item.json.co2 : 0;
        return sum + co2Value;
      }, 0) / allCO2Data.length),
      minCO2: Math.min(...allCO2Data.map(item => {
        const co2Value = item.json.co2 !== null && item.json.co2 !== undefined ? item.json.co2 : 0;
        return co2Value;
      })),
      maxCO2: Math.max(...allCO2Data.map(item => {
        const co2Value = item.json.co2 !== null && item.json.co2 !== undefined ? item.json.co2 : 0;
        return co2Value;
      })),
      fileName: fileName,  // 新增檔案名稱到 JSON 輸出
      dayOfWeek: dayOfWeek  // 新增星期幾資訊
    },
    binary: {
      'co2_report': binaryData
    }
  }
];

// 取得輸入資料
const inputData = $input.all();

// 初始化結果陣列
const output = [];

// 處理每個輸入項目
for (const item of inputData) {
  const json = item.json;

  // 計算 room_id 陣列的大小
  let roomIdCount = 0;

  if (json.room_id && Array.isArray(json.room_id)) {
    roomIdCount = json.room_id.length;
  }

  // 計算 client_name 陣列的大小（額外提供）
  let clientNameCount = 0;

  if (json.client_name && Array.isArray(json.client_name)) {
    clientNameCount = json.client_name.length;
  }

  // 輸出結果
  output.push({
    json: {
      room_id_count: roomIdCount,
      client_name_count: clientNameCount,
      original_data: json
    }
  });
}

return output;

// n8n Code Node - CO2 Statistics Calculator (Integer Output)
// This code calculates min, max, average, and median from the CO2 array as integers

const items = $input.all();
let co2Values = [];

// Extract CO2 values from each item
for (const item of items) {
  if (item.json.CO2) {
    if (Array.isArray(item.json.CO2)) {
      co2Values = co2Values.concat(item.json.CO2);
    } else {
      co2Values.push(item.json.CO2);
    }
  }
  if (item.json.co2) {
    if (Array.isArray(item.json.co2)) {
      co2Values = co2Values.concat(item.json.co2);
    } else {
      co2Values.push(item.json.co2);
    }
  }
}

// Convert all values to numbers and filter out invalid entries
co2Values = co2Values
  .map(val => parseFloat(val))
  .filter(val => !isNaN(val));

// Function to calculate integer-based statistics
function calculateStatistics(values) {
  if (values.length === 0) {
    return { error: "No valid CO2 values found", count: 0 };
  }

  const sortedValues = [...values].sort((a, b) => a - b);

  const min = Math.round(Math.min(...values));
  const max = Math.round(Math.max(...values));
  const sum = values.reduce((acc, val) => acc + val, 0);
  const average = Math.round(sum / values.length);

  let median;
  const middleIndex = Math.floor(sortedValues.length / 2);

  if (sortedValues.length % 2 === 0) {
    median = Math.round((sortedValues[middleIndex - 1] + sortedValues[middleIndex]) / 2);
  } else {
    median = Math.round(sortedValues[middleIndex]);
  }

  return {
    min,
    max,
    average,
    median,
    count: values.length,
    allValues: values.map(v => Math.round(v))
  };
}

const statistics = calculateStatistics(co2Values);

return [{
  json: {
    co2_statistics: {
      minimum: statistics.min,
      maximum: statistics.max,
      average: statistics.average,
      median: statistics.median,
      total_count: statistics.count
    },
    raw_co2_values: statistics.allValues,
    calculated_at: new Date().toISOString()
  }
}];

// 取得輸入資料
const inputData = $input.all();

// 初始化結果陣列
const output = [];

// 處理每個輸入項目
for (const item of inputData) {
  const json = item.json;

  // 計算 room_id 陣列的大小
  let roomIdCount = 0;

  if (json.room_id && Array.isArray(json.room_id)) {
    roomIdCount = json.room_id.length;
  }

  // 計算 client_name 陣列的大小（額外提供）
  let clientNameCount = 0;

  if (json.client_name && Array.isArray(json.client_name)) {
    clientNameCount = json.client_name.length;
  }

  // 輸出結果
  output.push({
    json: {
      room_id_count: roomIdCount,
      client_name_count: clientNameCount,
      original_data: json
    }
  });
}

return output;
